1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number; previousContracts?: number };
3	  items: {
4	    type: string;
5	    material?: string;
6	    cursed?: boolean;
7	    enchantment?: number;
8	  }[];
9	}
10	
11	const PROCESSING_FEE = 5;
12	
13	const BLOCK_SIZE = 3;
14	const BLOCK_PRICE = 60;
15	
16	const CURSE_SURCHARGE_RATE = 0.5;
17	
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	
21	const LOYALTY_MINIMUM_YEARS = 2;
22	const LOYALTY_DISCOUNT_RATE = 0.2;
23	
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	
26	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
27	
28	// Premiums are rounded up to whole G, in MHPCO's favour.
29	const roundUpToWholeG = (amount: number): number => Math.ceil(amount);
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	export function quote(input: QuoteInput): number {
41	  const countsByType: Record<string, number> = {};
42	  for (const item of input.items) {
43	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
44	  }
45	
46	  let basePremiumTotal = 0;
47	  for (const type of Object.keys(countsByType)) {
48	    const count = countsByType[type];
49	    if (count === BLOCK_SIZE) {
50	      basePremiumTotal += BLOCK_PRICE;
51	    } else {
52	      basePremiumTotal += count * BASE_PREMIUMS[type];
53	    }
54	  }
55	
56	  const isFirstInsurance = input.customer?.previousContracts !== undefined;
57	
58	  let surchargeTotal = 0;
59	  for (const item of input.items) {
60	    const itemBasePremium = BASE_PREMIUMS[item.type];
61	    if (item.cursed) {
62	      surchargeTotal += itemBasePremium * CURSE_SURCHARGE_RATE;
63	    }
64	    if (
65	      item.enchantment !== undefined &&
66	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
67	    ) {
68	      surchargeTotal += itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE;
69	    }
70	    if (isFirstInsurance) {
71	      surchargeTotal += itemBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
72	    }
73	  }
74	
75	  const isLoyal =
76	    (input.customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MINIMUM_YEARS;
77	  const isFollowUp = (input.customer?.previousContracts ?? 0) >= 1;
78	
79	  const loyaltyDiscount = isLoyal ? basePremiumTotal * LOYALTY_DISCOUNT_RATE : 0;
80	  const followUpDiscount = isFollowUp
81	    ? basePremiumTotal * FOLLOW_UP_DISCOUNT_RATE
82	    : 0;
83	
84	  const rawPremium =
85	    basePremiumTotal -
86	    loyaltyDiscount -
87	    followUpDiscount +
88	    surchargeTotal +
89	    PROCESSING_FEE;
90	
91	  return roundUpToWholeG(rawPremium);
92	}
