94	export interface ClaimInput {
95	  items: { type: string; material?: string; enchantment?: number }[];
96	  remainingCap?: number;
97	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
98	}
99	
100	export interface ClaimResult {
101	  payout: number;
102	  // The cap left over after this claim, so successive claims can be chained by
103	  // passing it back in as ClaimInput.remainingCap. Optional because callers who
104	  // only need the payout can ignore it.
105	  remainingCap?: number;
106	}
107	
108	const DEDUCTIBLE = 100;
109	
110	const INSURANCE_VALUES: Record<string, number> = {
111	  sword: 1000,
112	  amulet: 600,
113	  staff: 800,
114	  potion: 400,
115	  rune: 250,
116	  moonstone: 250,
117	};
118	
119	const CAP_MULTIPLIER = 2;
120	
121	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
122	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
123	
124	const hasHighEnchantment = (
125	  item: ClaimInput["items"][number] | undefined,
126	): boolean =>
127	  item?.enchantment !== undefined &&
128	  item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
129	
130	// Reimbursement for a single damage, before the deductible is applied.
131	const reimbursementBeforeDeductible = (
132	  item: ClaimInput["items"][number] | undefined,
133	  damageAmount: number,
134	): number =>
135	  hasHighEnchantment(item)
136	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
137	    : damageAmount;
138	
139	// The total payout is capped at a multiple of the unmodified insurance sum.
140	const payoutCap = (items: ClaimInput["items"]): number => {
141	  const insuranceSum = items.reduce(
142	    (total, item) => total + INSURANCE_VALUES[item.type],
143	    0,
144	  );
145	  return CAP_MULTIPLIER * insuranceSum;
146	};
147	
148	export function claim(input: ClaimInput): ClaimResult {
149	  const rawPayout = input.incident.damages.reduce((total, damage) => {
150	    const item = input.items.find((i) => i.type === damage.itemType);
151	    const reimbursed = reimbursementBeforeDeductible(item, damage.amount);
152	    return total + (reimbursed - DEDUCTIBLE);
153	  }, 0);
154	
155	  const availableRemainingCap = input.remainingCap ?? payoutCap(input.items);
156	  const payout = Math.min(rawPayout, availableRemainingCap);
157	  return { payout, remainingCap: availableRemainingCap - payout };
158	}
